  ('aboriginal-0a2fc18c-moex-00146', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設某商品合乎供給法則與需求法則。當政府調高該商品的單位稅額時，下列敘述何者正確？', '["稅收金額必定增加", "稅收金額必定減少", "無謂損失增加", "無謂損失減少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00147', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設世界經濟體有甲國、乙國生產汽車與機械，且根據比較利益原則完全專業化生產並進行貿易。 如下圖所示，兩國之生產可能線均為直線。今若甲國機械生產發生技術進步，生產力變為原來的 2倍，下列敘述何者錯誤？', '["甲國生產機械的機會成本變低", "技術變動後甲國在兩種產品的生產上均具絕對利益", "甲國改為出口機械、進口汽車", "技術變動後，世界總產出增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00148', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '有關需求彈性，下列敘述何者正確？', '["彈性之大小不受商品與價格之衡量單位所影響", "需求曲線斜率越大則需求彈性越大", "需求曲線為一直線，則線上每一點之彈性皆相同", "需求曲線斜率越大則所得彈性越小"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00149', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設某廠商在產量為Q1時，其平均總成本最小。當廠商在Q1下增加產量時，下列敘述何者正確？', '["邊際成本、平均變動成本與平均固定成本都增加", "邊際成本、平均變動成本與平均固定成本都減少", "邊際成本與平均變動成本都增加，但平均固定成本減少", "邊際成本增加，但平均變動成本與平均固定成本都減少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00150', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '一家利潤極大化之廠商發現如果它持續營運，即使它選擇利潤極大之產品數量X，它仍面臨虧損。 在數量X時，下列何種情形下該廠商應該停止生產？', '["單位平均收益較短期平均成本為低", "單位平均收益較平均變動成本為低", "邊際收益較短期平均成本為低", "邊際收益較平均變動成本為低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00151', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '廠商進行差別取價時，應對價格彈性較小的客人收取何種價格？', '["收取低價，以薄利多銷策略增加利潤", "收取高價，拿取其消費者剩餘", "將消費者心中願付價格較低的產品與願付價格較高的產品綑綁起來銷售、並折價賣出", "以P=MC之水準的價格賣出；P為價格、MC為邊際成本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00152', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-112-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '有關獨占性競爭廠商，下列敘述何者錯誤？', '["它面對的是一條負斜率的需求曲線", "長期而言，該廠商的利潤為零", "該廠商之產品價格會等於其邊際成本", "該廠商與其競爭者所面臨之需求曲線可能各不相同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:41+00:00", "source_pdf_sha1": "ce417e5dc7ec", "answer_pdf_sha1": "1ed4482d7d49", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "509", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL)
